#!/usr/bin/env bash
# workflow-7.sh — 机构合规风控与投诉处理（资质 / 广告 / 价格 / 票据 / 病历） SOP walkthrough for 医疗美容.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="医疗美容"
WORKFLOW="机构合规风控与投诉处理（资质 / 广告 / 价格 / 票据 / 病历）"

usage() {
  cat <<EOF
workflow-7.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-7.sh             # interactive
  ./workflow-7.sh --dry-run
  ./workflow-7.sh --json
  ./workflow-7.sh --explain
  ./workflow-7.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "机构合规风控与投诉处理（资质 / 广告 / 价格 / 票据 / 病历）" 工作流。

一句话: 从「机构上新项目/发广告/处理纠纷」到「资质-广告-票据-病历四道合规闭环 + 投诉化解」——把监管红线变成可执行的日常风控 SOP。

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 医美的第一性是医疗，不是消费: 医疗美容首先是外科与皮肤科的**医疗行为**（可致盲、致残、致死），不是快消品；任何决策的第一约束是安全与合规，不是美学最大化或转化率。
  • 先安全后审美：风险分层判断: 资深人的核心能力不是「打得漂亮」，而是**在安全处提效、在危险处零妥协**——知道哪一步能省、哪一步一步都不能省。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**资质合规**：机构持《医疗机构执业许可证》且诊疗科目含「医疗美容科」；医生持《医师执业证书》+ 医美主诊医师备案（美容外科 6 年/牙 5 年/皮肤·中医 3 年临床门槛，每人限一专业）；项目按一至四级分级准入。 evidence: [T03-S001, T03-S011, T03-S012]"
  "**广告合规**：发布前取得《医疗广告审查证明》；内容遵「八不准」+ 不制造容貌焦虑/不疗效保证/不对比图/不软文伪科普。 evidence: [T03-S002]"
  "**价格与票据合规**：明码标价、规范开票，不做虚假折扣/钓鱼低价/医美贷套路诱导。 evidence: [T03-S002, T03-S015]"
  "**病历与术前照合规**：完整电子病历 + 知情同意 + 术前标准照 + 随访记录，加密合规存储。 evidence: [T03-S001]"
  "**投诉处理**：建立投诉响应流程，区分「效果不达预期」（沟通/修复/退费协商）vs「医疗并发症/事故」（先医疗处置+按医疗纠纷流程，必要时转诊/上报）。"
)
declare -a FAILURE_MODES=(
  "**无备案医生/超分级操作**：actionable—上岗前核验主诊备案与项目分级，缺一即非法行医。"
  "**广告未前置审查/用对比图**：actionable—任何对外内容先过广告合规，对比图/疗效保证/焦虑文案一律不发。"
  "**病历术前照缺失**：actionable—操作前强制完成知情同意+术前照，否则纠纷举证必输。"
  "**把医疗并发症当效果争议拖延**：actionable—并发症先医疗处置+按纠纷流程，不可当退费协商拖延致恶化。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-7-walkthrough"
fi
